(function(w){"use strict";const ID="prime-check",MAX=18446744073709551615n;function parse(v){const s=String(v??"").replace(/,/g,"").trim();if(!/^\d+$/.test(s))return null;try{return BigInt(s)}catch(_){return null}}function modPow(a,d,n){let r=1n;a%=n;while(d>0n){if(d&1n)r=r*a%n;a=a*a%n;d>>=1n}return r}function isPrime(n){if(n<2n)return false;for(const p of [2n,3n,5n,7n,11n,13n,17n,19n,23n,29n,31n,37n]){if(n===p)return true;if(n%p===0n)return false}let d=n-1n,s=0;while((d&1n)===0n){d>>=1n;s++}for(const a0 of [2n,325n,9375n,28178n,450775n,9780504n,1795265022n]){const a=a0%n;if(a===0n)continue;let x=modPow(a,d,n);if(x===1n||x===n-1n)continue;let witness=true;for(let r=1;r<s;r++){x=x*x%n;if(x===n-1n){witness=false;break}}if(witness)return false}return true}function compute(x){const n=parse(x.n);if(n===null)return{error:"0 이상의 정수를 입력해 주세요."};if(n>MAX)return{error:"정확한 판정을 위해 18,446,744,073,709,551,615 이하의 정수를 입력해 주세요."};const ok=isPrime(n);return{isPrime:ok,label:ok?"소수입니다":"소수가 아닙니다"}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-prime-n">정수</label><input id="hm-prime-n" class="hm-calc-input" inputmode="numeric" placeholder="예: 97"><p class="hm-calc-hint">64비트 범위 안에서 정확하게 판정합니다.</p></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">소수 판별</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const n=root.querySelector("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({n:n.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("판별 결과",r.label));});reset.addEventListener("click",()=>{n.value="";api.setMessage(msg,"");api.clearResult(res);n.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
